def triage_request(form: dict) -> tuple[str, str]:
    """
    Returns (request_type, reason).
    request_type: "tier2_gate" | "tier3_advisory"
    """
    tier2_triggers = []

    if form["output_action"] == "Decide":
        tier2_triggers.append("output action is 'Decide' (consequential decision)")

    if form["pii_in_prompts"] in ("Yes", "Unsure"):
        tier2_triggers.append("PII in prompts (actual or possible)")

    if form["user_population"] in ("Customers", "Third parties"):
        tier2_triggers.append("external user-facing deployment")

    if form["data_classification"] in ("Confidential", "Restricted"):
        tier2_triggers.append("confidential or restricted data in context")

    if form["estimated_monthly_calls"] > 1_000_000:
        tier2_triggers.append("high volume (> 1M calls/month); cost and policy review required")

    if tier2_triggers:
        reason = "; ".join(tier2_triggers)
        return "tier2_gate", f"Tier 2 review required: {reason}"

    return "tier3_advisory", "No Tier 2 triggers; routing to advisory track"
